<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';require_once dirname(__DIR__,2).'/includes/audit.php';exigirPermiso('academic.grades.manage');if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$pdo=obtenerConexion();$docenteId=docenteSupervisadoAtenea($pdo);$entregaId=docenteId($_POST['entrega_id']??0);$nota=(string)($_POST['nota']??'');$observacion=trim(strip_tags((string)($_POST['observacion']??'')));try{$pdo->beginTransaction();$q=$pdo->prepare('SELECT ee.id,ee.estudiante_id,ee.evaluacion_id,e.asignatura_id,e.nota_maxima FROM ev_entregadas ee JOIN evaluaciones e ON e.id=ee.evaluacion_id WHERE ee.id=:id AND e.docente_id=:d FOR UPDATE');$q->execute(['id'=>$entregaId,'d'=>$docenteId]);$e=$q->fetch();if(!$e||!docentePuedeEstudiante($pdo,$docenteId,(int)$e['estudiante_id'],(int)$e['asignatura_id']))throw new DomainException('La entrega no pertenece a tus cursos.');if(!is_numeric($nota)||(float)$nota<0||(float)$nota>(float)$e['nota_maxima']||mb_strlen($observacion)>1000)throw new DomainException('La calificación no es válida.');$valor=number_format((float)$nota,2,'.','');$q=$pdo->prepare('SELECT * FROM notas WHERE entrega_id=:id FOR UPDATE');$q->execute(['id'=>$entregaId]);$anterior=$q->fetch();if($anterior){$pdo->prepare('UPDATE notas SET nota=:n,observacion=:o,calificado_por=:u WHERE id=:id')->execute(['n'=>$valor,'o'=>$observacion?:null,'u'=>$_SESSION['usuario_id'],'id'=>$anterior['id']]);$notaId=(int)$anterior['id'];}else{$pdo->prepare('INSERT INTO notas(entrega_id,evaluacion_id,estudiante_id,docente_id,nota,observacion,calificado_por) VALUES(:en,:ev,:es,:d,:n,:o,:u)')->execute(['en'=>$entregaId,'ev'=>$e['evaluacion_id'],'es'=>$e['estudiante_id'],'d'=>$docenteId,'n'=>$valor,'o'=>$observacion?:null,'u'=>$_SESSION['usuario_id']]);$notaId=(int)$pdo->lastInsertId();}$pdo->prepare('INSERT INTO notas_historial(nota_id,nota_anterior,nota_nueva,observacion_anterior,observacion_nueva,cambiado_por) VALUES(:id,:a,:n,:oa,:on,:u)')->execute(['id'=>$notaId,'a'=>$anterior['nota']??null,'n'=>$valor,'oa'=>$anterior['observacion']??null,'on'=>$observacion?:null,'u'=>$_SESSION['usuario_id']]);$pdo->prepare("UPDATE ev_entregadas SET estado='revisada' WHERE id=:id")->execute(['id'=>$entregaId]);registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'target_user_id'=>$e['estudiante_id'],'event_type'=>'academic.grade.saved','module'=>'academic','entity_type'=>'grade','entity_id'=>$notaId,'action'=>'update','result'=>'success','description'=>'Calificación registrada en una entrega autorizada.'], $pdo);$pdo->commit();docenteFlash('exito','Calificación guardada.');}catch(Throwable $x){if($pdo->inTransaction())$pdo->rollBack();docenteFlash('error',$x instanceof DomainException?$x->getMessage():'No fue posible guardar la calificación.');}header('Location:'.docenteUrl('entregas.php',['evaluacion'=>$e['evaluacion_id']??0]));
